110→function slugify(text: string): string {
111→  return text
112→    .toLowerCase()
113→    .normalize('NFD')
114→    .replace(/[\u0300-\u036f]/g, '')
115→    .replace(/[^a-z0-9]+/g, '-')
116→    .replace(/^-+|-+$/g, '')
117→    .slice(0, 60);
118→}
