120→function logTimestamp(): string {
121→  const d = new Date();
122→  return `${d.toISOString().slice(0, 10)}_${d.toISOString().slice(11, 19).replace(/:/g, '')}`;
123→}
124→
125→function logFilePath(slug: string): string {
126→  return `${LOG_DIR}/${logTimestamp()}_${slug}.log`;
127→}
