129→class LogBuffer {
130→  private buf: string[] = [];
131→  private timer: ReturnType<typeof setInterval> | null = null;
132→  private path: string;
133→
134→  constructor(
135→    initialPath: string,
136→    private readonly flushMs: number,
137→  ) {
138→    this.path = initialPath;
139→    this.timer = setInterval(() => this.flush(), this.flushMs);
140→    if (this.timer && typeof this.timer === 'object' && 'unref' in this.timer) {
141→      (this.timer as NodeJS.Timeout).unref();
142→    }
143→  }
144→
145→  write(raw: string): void {
146→    this.buf.push(stripAnsi(raw));
147→  }
148→
149→  flush(): void {
150→    if (this.buf.length === 0) return;
151→    const chunk = this.buf.join('');
152→    this.buf.length = 0;
153→    try {
154→      appendFileSync(this.path, chunk);
155→    } catch (err) {
156→      console.error(`[LogBuffer] write failed: ${err}`);
157→    }
158→  }
159→
160→  startNewFile(newPath: string): void {
161→    this.flush();
162→    this.path = newPath;
163→  }
164→
165→  renameFile(newPath: string): void {
166→    this.flush();
167→    try {
168→      renameSync(this.path, newPath);
169→      this.path = newPath;
170→    } catch {}
171→  }
172→
173→  currentPath(): string {
174→    return this.path;
175→  }
176→
177→  dispose(): void {
178→    if (this.timer) clearInterval(this.timer);
179→    this.flush();
180→  }
181→}
182→
183→const logBuffer = new LogBuffer(
184→  logFilePath('startup'),
185→  CONFIG.logFlushInterval,
186→);
