188→type Color = 'green' | 'yellow' | 'red' | 'blue' | 'blackBright';
189→
190→function print(message: string, color?: Color): void {
191→  const colored = color ? chalk[color](message) : message;
192→  process.stdout.write(colored);
193→  logBuffer.write(message);
194→}
195→
196→function println(message = '', color?: Color): void {
197→  const ts = new Date().toISOString().replace('T', ' ').slice(0, 19);
198→  print(`[${ts}] ${message}\n`, color);
199→}
200→
201→function syslog(message = '', color?: Color): void {
202→  println(`‣ ${message}`, color);
203→}
