205→async function dispatchSafe<T, C>(
206→  hook: { dispatch: (value: T, context: C) => Promise<T> },
207→  name: string,
208→  value: T,
209→  context: C
210→): Promise<T> {
211→  try {
212→    return await hook.dispatch(value, context);
213→  } catch (err) {
214→    syslog(`Hook "${name}" error: ${err}`, 'red');
215→    return value;
216→  }
217→}
