283→interface ContentBlock {
284→  type: 'text' | 'tool_use' | 'tool_result';
285→  text?: string;
286→  name?: string;
287→  input?: unknown;
288→  content?:
289→    | string
290→    | Array<{
291→        type: string;
292→        text?: string;
293→      }>;
294→}
295→
296→interface StreamMessage {
297→  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
298→  subtype?: string;
299→  role?: 'assistant' | 'user';
300→  event?: {
301→    type: string;
302→    delta?: {
303→      type: string;
304→      text?: string;
305→    };
306→  };
307→  result?: string;
308→  message?: {
309→    role?: string;
310→    content?: ContentBlock[];
311→  };
312→  content?: ContentBlock[];
313→}
