586→async function main(): Promise<void> {
587→  let cleanupCalled = false;
588→
589→  const cleanup = (signal: string) => {
590→    if (cleanupCalled) return;
591→    cleanupCalled = true;
592→    try {
593→      hooks.cleanup.dispatch(signal, undefined);
594→    } catch (err) {
595→      console.error(`[cleanup hook error] ${err}`);
596→    }
597→    println();
598→    syslog(`Interrupted by ${signal}. Cleaning up...`);
599→    killCurrentProc();
600→    logBuffer.dispose();
601→    process.exit(signal === 'SIGINT' ? 130 : 143);
602→  };
603→
604→  process.on('SIGINT', () => cleanup('SIGINT'));
605→  process.on('SIGTERM', () => cleanup('SIGTERM'));
606→
607→  await checkDependencies();
608→
609→  printHeader();
610→  syslog('Starting automated task loop...');
611→
612→  await dispatchSafe(hooks.loopStart, 'loopStart', CONFIG, undefined);
613→
614→  let consecutiveFailures = 0;
615→  let iteration = 0;
616→  const BACKOFF_BASE_MS = 60_000;
617→  const BACKOFF_MAX_MS = 5 * 60 * 60_000;
618→
619→  while (iteration < CONFIG.maxIterations) {
620→    archiveCompletedTasks();
621→
622→    const attemptNum = iteration + 1;
623→    logBuffer.startNewFile(logFilePath(`iter-${attemptNum}`));
624→
625→    const iterCtx: IterationContext = {
626→      iteration: attemptNum,
627→      maxIterations: CONFIG.maxIterations,
628→      logPath: logBuffer.currentPath(),
629→    };
630→
631→    println();
632→    println('==========================================', 'green');
633→    syslog(`Iteration #${attemptNum} / ${CONFIG.maxIterations}`, 'green');
634→    syslog(`Log: ${logBuffer.currentPath()}`, 'green');
635→    println('==========================================', 'green');
636→    println();
637→
638→    await dispatchSafe(
639→      hooks.iterationStart,
640→      'iterationStart',
641→      iterCtx,
642→      undefined,
643→    );
644→
645→    const result = await runIteration();
646→    const { output, exitCode, timedOut } = result;
647→
648→    if (exitCode === 0) {
649→      syslog('Claude Code completed successfully', 'green');
650→      consecutiveFailures = 0;
651→      await dispatchSafe(
652→        hooks.iterationSuccess,
653→        'iterationSuccess',
654→        result,
655→        iterCtx,
656→      );
657→    } else if (timedOut) {
658→      syslog(
659→        'Iteration timed out — progress may persist in progress.txt',
660→        'yellow',
661→      );
662→      consecutiveFailures = 0;
663→      await dispatchSafe(
664→        hooks.iterationTimeout,
665→        'iterationTimeout',
666→        result,
667→        iterCtx,
668→      );
669→    } else {
670→      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
671→      consecutiveFailures++;
672→
673→      const failCtx: FailureContext = {
674→        ...iterCtx,
675→        exitCode,
676→        consecutiveFailures,
677→      };
678→      await dispatchSafe(
679→        hooks.iterationFailure,
680→        'iterationFailure',
681→        result,
682→        failCtx,
683→      );
684→
685→      const backoffMs = Math.min(
686→        BACKOFF_BASE_MS * Math.pow(2, consecutiveFailures - 1),
687→        BACKOFF_MAX_MS,
688→      );
689→      const backoffMin = (backoffMs / 60_000).toFixed(1);
690→
691→      const backoffCtx: BackoffContext = {
692→        ...failCtx,
693→        backoffMs,
694→      };
695→      const skipBackoff = await dispatchSafe(
696→        hooks.shouldSkipBackoff,
697→        'shouldSkipBackoff',
698→        false,
699→        backoffCtx,
700→      );
701→
702→      if (skipBackoff === true) {
703→        syslog('Backoff skipped by hook', 'yellow');
704→      } else {
705→        println();
706→        println('==========================================', 'yellow');
707→        syslog(
708→          `${consecutiveFailures} consecutive failure(s) — retrying in ${backoffMin}min`,
709→          'yellow',
710→        );
711→        println('==========================================', 'yellow');
712→        await Bun.sleep(backoffCtx.backoffMs);
713→      }
714→      continue;
715→    }
716→
717→    iteration++;
718→
719→    const rawStatus = parseRalphStatus(output);
720→    const status = await dispatchSafe(
721→      hooks.resolveStatus,
722→      'resolveStatus',
723→      rawStatus,
724→      output,
725→    );
726→    const taskSlug = status
727→      ? slugify(status.task)
728→      : timedOut
729→        ? 'timeout'
730→        : 'no-status';
731→    logBuffer.renameFile(logFilePath(taskSlug));
732→
733→    if (status?.exit) {
734→      await dispatchSafe(
735→        hooks.allTasksComplete,
736→        'allTasksComplete',
737→        status,
738→        iteration,
739→      );
740→      println();
741→      println('==========================================', 'green');
742→      syslog('ALL TASKS COMPLETED!', 'green');
743→      syslog(`Final task:      ${status.task}`, 'green');
744→      syslog(`Remaining:       ${status.remaining}`, 'green');
745→      syslog(`Total iterations: ${iteration}`, 'green');
746→      println('==========================================', 'green');
747→      logBuffer.dispose();
748→      process.exit(0);
749→    }
750→
751→    if (status) {
752→      await dispatchSafe(hooks.taskComplete, 'taskComplete', status, iterCtx);
753→      syslog(
754→        `Task done: "${status.task}" — ${status.remaining} remaining`,
755→        'blue',
756→      );
757→    } else if (!timedOut && exitCode === 0) {
758→      syslog(
759→        'Warning: No RALPH_STATUS found in output. Claude may not have followed the protocol.',
760→        'yellow',
761→      );
762→    }
763→
764→    if (iteration < CONFIG.maxIterations) {
765→      const delaySec = CONFIG.delayBetweenIterations / 1_000;
766→      println();
767→      syslog(`Waiting ${delaySec}s before next iteration...`);
768→      await Bun.sleep(CONFIG.delayBetweenIterations);
769→    }
770→  }
771→
772→  await dispatchSafe(hooks.loopEnd, 'loopEnd', iteration, undefined);
773→
774→  println();
775→  println('==========================================', 'red');
776→  syslog(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
777→  syslog('Loop stopped — tasks may still be pending', 'red');
778→  println('==========================================', 'red');
779→  logBuffer.dispose();
780→  process.exit(1);
781→}
